const AWS = require('aws-sdk');
const s3 = new AWS.S3();

exports.handler = async (event) => {
    try {
        const bucket = event.Records[0].s3.bucket.name;
        const key = event.Records[0].s3.object.key;
        
        // Get the file from the source S3
        const params = {
            Bucket: bucket,
            Key: key
        };
        const inputFile = await s3.getObject(params).promise();
        
        // Process the file
        const processedData = processFile(inputFile.Body);
        
        // Define destination S3 Bucket and Key
        const destinationBucket = 'processed-bucket';
        const destinationKey = `processed/${key}`;
        
        // Save the processed file to the destination S3
        const putParams = {
            Bucket: destinationBucket,
            Key: destinationKey,
            Body: processedData
        };
        await s3.putObject(putParams).promise();
        
        return { status: 'File processed and saved successfully' };
    } catch (error) {
        console.error(error);
        throw new Error('File processing failed');
    }
};

